INSERT INTO page_content (project_id, section_id, draft_text, published_text) VALUES
('majdamartinska', 'home.hero.label', 'RODINNÉ · SVATEBNÍ · NEWBORN FOCENÍ', 'RODINNÉ · SVATEBNÍ · NEWBORN FOCENÍ'),
